          Cancel
        </button>
        <button
          type="submit"
          disabled={saving || !repository.trim()}
          className="rounded-md px-3 py-1 text-[12px] font-medium text-white disabled:opacity-40"
          style={{ backgroundColor: "#e8601a" }}
